import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return an empty grid when given an empty grid");
  it.todo("should kill a single live cell with 0 neighbors");
  it.todo("should kill two adjacent live cells (each has 1 neighbor)");
  it.todo("should keep a 2x2 block unchanged (still life)");
  it.todo("should transform a vertical blinker into a horizontal blinker");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors");
  it.todo("should kill cells with more than 3 neighbors and revive corners in a full 3x3 block");
  it.todo("should support negative coordinates on the infinite grid");
});
